23	 *
24	 * Processes batched activity events and inserts them into the database.
25	 * Uses Inngest's batch feature for efficient processing.
26	 */
27	export const recordActivity = inngest.createFunction(
28	  {
29	    id: "console/record-activity",
30	    name: "Record Activity",
31	    description: "Batch record user activities for efficient database writes",
32	    retries: 3,
33	
