48	    // Guard: Inngest's batchEvents config should never deliver an empty array,
49	    // but defend against it to avoid a Postgres error on INSERT with no values.
50	    if (events.length === 0) {
51	      log.warn("Received empty activity batch, skipping");
52	      return {
53	        success: true,
54	        clerkOrgId: undefined,
55	        batchSize: 0,
56	        insertedCount: 0,
57	        timestamp: new Date().toISOString(),
58	      };
59	    }
60	
61	    const batchSize = events.length;
62	    // Safe after the length guard above
63	    const clerkOrgId = events[0].data.clerkOrgId;
64	
65	    log.info("Processing activity batch", {
66	      batchSize,
67	      clerkOrgId,
68	      firstEventTimestamp: events[0].ts,
69	      lastEventTimestamp: events.at(-1)?.ts,
70	    });
