85	          metadata: data.metadata as ActivityMetadata,
86	          relatedActivityId: data.relatedActivityId ?? null,
87	        };
88	      });
89	    });
90	
91	    // Step 2: Batch insert activities
92	    const insertResult = await step.run("activity.batch-insert", async () => {
93	      try {
94	        // Use Drizzle's batch insert for optimal performance
95	        const result = await db
