/**
 * Memory service tRPC initialization.
 *
 * Auth model: service-to-service JWT (not Clerk).
 * All callers are internal services (console, platform, inngest, cron).
 */
import { nanoid } from "@repo/lib";
import { trpcMiddleware } from "@sentry/core";
import { initTRPC, TRPCError } from "@trpc/server";
import { log } from "@vendor/observability/log/next";
import { emitJournal, withRequestContext } from "@vendor/observability/request";
import superjson from "superjson";
import { ZodError } from "zod";

import { verifyServiceJWT } from "./lib/jwt";

// -- Auth Context -------------------------------------------------------------

/**
 * Discriminated union for memory service authentication.
 * Every request resolves to exactly one variant.
 */
export type MemoryAuthContext =
  | { type: "service"; caller: string }
  | { type: "webhook"; provider: string }
  | { type: "inngest" }
  | { type: "cron" }
  | { type: "unauthenticated" };

// -- Context Creation ---------------------------------------------------------

/**
 * Create tRPC context for memory service requests.
 *
 * Auth resolution order:
 * 1. Bearer JWT in Authorization header -> service auth
 * 2. X-Memory-Source header for internal identification
 * 3. Unauthenticated fallback
 */
export const createMemoryTRPCContext = async (opts: { headers: Headers }) => {
  const source = opts.headers.get("x-trpc-source") ?? "unknown";

  // Check for service JWT in Authorization header
  const authHeader = opts.headers.get("authorization");
  if (authHeader?.startsWith("Bearer ")) {
    const token = authHeader.replace("Bearer ", "");

    try {
      const verified = await verifyServiceJWT(token);
      log.info("[trpc] memory service request", {
        source,
        auth: "service",
        caller: verified.caller,
      });
      return {
        auth: {
          type: "service" as const,
          caller: verified.caller,
        },
        headers: opts.headers,
      };
    } catch (error) {
      log.warn("[trpc] JWT verification error", {
        source,
        error: error instanceof Error ? error.message : String(error),
      });
    }
  }

  // No authentication
  log.info("[trpc] memory service request", {
    source,
    auth: "unauthenticated",
  });
  return {
    auth: { type: "unauthenticated" as const },
    headers: opts.headers,
  };
};

// -- tRPC Initialization ------------------------------------------------------

const isProduction = process.env.NODE_ENV === "production";

const t = initTRPC.context<typeof createMemoryTRPCContext>().create({
  transformer: superjson,
  errorFormatter: ({ shape, error }) => {
    const shouldSanitize =
      isProduction && error.code === "INTERNAL_SERVER_ERROR";

    return {
      ...shape,
      message: shouldSanitize ? "An unexpected error occurred" : shape.message,
      data: {
        ...shape.data,
        zodError:
          error.cause instanceof ZodError ? error.cause.flatten() : null,
      },
    };
  },
});

// -- Middleware ----------------------------------------------------------------

const sentryMiddleware = t.middleware(
  trpcMiddleware({
    attachRpcInput: true,
  }),
);

const sentrifiedProcedure = t.procedure.use(sentryMiddleware);

const observabilityMiddleware = t.middleware(
  async ({ next, path, ctx, type }) => {
    if (t._config.isDev) {
      const waitMs = Math.floor(Math.random() * 400) + 100;
      await new Promise((resolve) => setTimeout(resolve, waitMs));
    }

    const { result, journal, durationMs } = await withRequestContext(
      {
        requestId: nanoid(),
        ...(ctx.auth.type === "service" && { caller: ctx.auth.caller }),
      },
      () => next(),
    );

    const meta = {
      path,
      type,
      durationMs,
      ok: result.ok,
      ...(!result.ok && { errorCode: result.error?.code }),
      ...(ctx.auth.type === "service" && { caller: ctx.auth.caller }),
    };

    if (result.ok) {
      log.info("[trpc] procedure completed", meta);
    } else {
      log.warn("[trpc] procedure failed", meta);
    }

    emitJournal(journal, { path, durationMs, ok: result.ok });

    return result;
  },
);

// -- Router & Procedure Exports -----------------------------------------------

export const createTRPCRouter = t.router;
export const createCallerFactory = t.createCallerFactory;

/**
 * Public procedure -- no auth required.
 * Use for health checks or publicly accessible endpoints.
 */
export const publicProcedure = sentrifiedProcedure.use(observabilityMiddleware);

/**
 * Service procedure -- requires valid service JWT.
 * Used by console, platform, or other internal services calling memory.
 *
 * Guarantees `ctx.auth.type === "service"` and `ctx.auth.caller` is available.
 */
export const serviceProcedure = sentrifiedProcedure
  .use(observabilityMiddleware)
  .use(({ ctx, next }) => {
    if (ctx.auth.type !== "service") {
      throw new TRPCError({
        code: "UNAUTHORIZED",
        message:
          "Service authentication required. Provide a valid service JWT in the Authorization header.",
      });
    }

    return next({
      ctx: {
        ...ctx,
        auth: ctx.auth as Extract<MemoryAuthContext, { type: "service" }>,
      },
    });
  });

/**
 * Admin procedure -- requires service JWT from an admin caller.
 * Used for administrative operations (reindex, purge, etc.).
 *
 * Restricts `ctx.auth.caller` to "admin" only.
 */
export const adminProcedure = sentrifiedProcedure
  .use(observabilityMiddleware)
  .use(({ ctx, next }) => {
    if (ctx.auth.type !== "service") {
      throw new TRPCError({
        code: "UNAUTHORIZED",
        message: "Service authentication required.",
      });
    }

    if (ctx.auth.caller !== "admin") {
      throw new TRPCError({
        code: "FORBIDDEN",
        message:
          "Admin access required. This endpoint is restricted to admin callers.",
      });
    }

    return next({
      ctx: {
        ...ctx,
        auth: ctx.auth as Extract<MemoryAuthContext, { type: "service" }>,
      },
    });
  });

import { backfillDepthSchema } from "@repo/app-providers/client";
import {
  backfillTriggerPayload,
  postTransformEventSchema,
} from "@repo/app-providers/contracts";
import { ingestionSourceSchema } from "@repo/app-validation";
import { z } from "zod";

export const memoryEvents = {
  // ── Backfill orchestration events ──
  "memory/backfill.run.requested": backfillTriggerPayload,
  "memory/backfill.run.cancelled": z.object({
    installationId: z.string(),
    correlationId: z.string().max(128).optional(),
  }),
  "memory/backfill.entity.requested": z.object({
    installationId: z.string(),
    provider: z.string(),
    orgId: z.string(),
    entityType: z.string(),
    resource: z.object({
      providerResourceId: z.string(),
      resourceName: z.string(),
    }),
    since: z.string().datetime(),
    depth: backfillDepthSchema,
    holdForReplay: z.boolean().optional(),
    correlationId: z.string().max(128).optional(),
  }),
  // ── Health check signal ──
  "memory/health.check.requested": z.object({
    /** Installation ID of the connection whose token was revoked */
    installationId: z.string(),
    /** Provider name (e.g. "github", "linear") */
    provider: z.string(),
    /** Why the health check is being requested */
    reason: z.enum(["401_unauthorized"]),
    /** Cross-service correlation ID for distributed tracing */
    correlationId: z.string().max(128).optional(),
  }),
  // ── Connection lifecycle (teardown) ──
  "memory/connection.lifecycle": z.object({
    installationId: z.string(),
    orgId: z.string(),
    provider: z.string(),
    reason: z.string(),
    triggeredBy: z.enum(["health_check", "user", "system"]),
    correlationId: z.string().optional(),
  }),
  // ── Ingest + neural pipeline events ──
  "memory/webhook.received": z.object({
    provider: z.string(),
    deliveryId: z.string(),
    eventType: z.string(),
    resourceId: z.string().nullable(),
    payload: z.unknown(),
    receivedAt: z.number(),
    preResolved: z
      .object({
        connectionId: z.string(),
        orgId: z.string(),
      })
      .optional(),
    correlationId: z.string().optional(),
  }),
  "memory/event.capture": z.object({
    clerkOrgId: z.string(),
    sourceEvent: postTransformEventSchema,
    ingestionSource: ingestionSourceSchema.optional(),
    ingestLogId: z.number().optional(),
    correlationId: z.string().optional(),
  }),
  "memory/event.stored": z.object({
    clerkOrgId: z.string(),
    eventExternalId: z.string(),
    sourceType: z.string(),
    significanceScore: z.number(),
  }),
  "memory/entity.upserted": z.object({
    clerkOrgId: z.string(),
    entityExternalId: z.string(),
    entityType: z.string(),
    provider: z.string(),
    internalEventId: z.number(),
    entityRefs: z.array(
      z.object({
        type: z.string(),
        key: z.string(),
        label: z.string().nullable(),
      })
    ),
    occurredAt: z.string(),
    correlationId: z.string().optional(),
  }),
  "memory/entity.graphed": z.object({
    clerkOrgId: z.string(),
    entityExternalId: z.string(),
    entityType: z.string(),
    provider: z.string(),
    occurredAt: z.string(),
    correlationId: z.string().optional(),
  }),
};

/**
 * Inngest exports for memory application
 *
 * Registered functions:
 * 1. ingestDelivery - Webhook delivery -> transform -> emit event.capture
 * 2. memoryEventStore - Event pipeline fast path (store facts + entities)
 * 3. memoryEntityGraph - Entity edge resolution via co-occurrence
 * 4. memoryEntityEmbed - Entity narrative embed to Pinecone layer="entities"
 * 5. memoryNotificationDispatch - High-significance event notifications via Knock
 * 6. memoryBackfillOrchestrator - Backfill orchestration (fan-out entity workers)
 * 7. memoryEntityWorker - Per-entity-type backfill pagination + dispatch
 * 8. connectionLifecycle - Connection teardown (close gate, revoke, cleanup)
 * 9. healthCheck - 5m cron: probe all active installations
 * 10. tokenRefresh - 5m cron: refresh expiring OAuth tokens
 * 11. deliveryRecovery - 5m cron: sweep stuck webhook deliveries
 */

import { serve } from "inngest/next";
import { inngest } from "./client";
import { connectionLifecycle } from "./functions/connection-lifecycle";
import { deliveryRecovery } from "./functions/delivery-recovery";
import { healthCheck } from "./functions/health-check";
import { ingestDelivery } from "./functions/ingest-delivery";
import { memoryBackfillOrchestrator } from "./functions/memory-backfill-orchestrator";
import { memoryEntityEmbed } from "./functions/memory-entity-embed";
import { memoryEntityGraph } from "./functions/memory-entity-graph";
import { memoryEntityWorker } from "./functions/memory-entity-worker";
import { memoryEventStore } from "./functions/memory-event-store";
import { memoryNotificationDispatch } from "./functions/memory-notification-dispatch";
import { tokenRefresh } from "./functions/token-refresh";

export { inngest };
export {
  ingestDelivery,
  memoryEventStore,
  memoryEntityGraph,
  memoryEntityEmbed,
  memoryNotificationDispatch,
  memoryBackfillOrchestrator,
  memoryEntityWorker,
  connectionLifecycle,
  healthCheck,
  tokenRefresh,
  deliveryRecovery,
};

/**
 * Create the Inngest route handler for Next.js
 */
export function createInngestRouteContext() {
  return serve({
    client: inngest,
    functions: [
      ingestDelivery,
      memoryEventStore,
      memoryEntityGraph,
      memoryEntityEmbed,
      memoryNotificationDispatch,
      memoryBackfillOrchestrator,
      memoryEntityWorker,
      connectionLifecycle,
      healthCheck,
      tokenRefresh,
      deliveryRecovery,
    ],
    servePath: "/api/inngest",
  });
}

